// The backend returns an array of site objects.
// We turn each site into its own n8n item so splitInBatches works correctly.

const sites = $input.first().json;

// Handle both array response and object-with-list response
const siteList = Array.isArray(sites) ? sites : (sites.sites || []);

return siteList.map(site => ({ json: site }));

// Merge scraped content with original site info
const site = $('One Site at a Time').first().json;
const firecrawlResponse = $input.first().json;

const markdown = firecrawlResponse?.data?.markdown || 
                 firecrawlResponse?.markdown || 
                 '';

if (!markdown || markdown.length < 50) {
  return [{
    json: {
      ...site,
      markdown: '',
      scrape_error: true,
      error_msg: 'Firecrawl returned empty content'
    }
  }];
}

return [{
  json: {
    ...site,
    markdown: markdown.slice(0, 8000), // Keep first 8000 chars (Gemini limit safety)
    scrape_error: false
  }
}];

