// Parse Gemini's response and extract the JSON analysis
const geminiResponse = $input.first().json;
const siteData = $('Merge Scraped Content').first().json;

let analysis;
try {
  // Gemini returns: {candidates: [{content: {parts: [{text: '...'}]}}]}
  const rawText = geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

  // Strip any accidental markdown code fences
  const cleaned = rawText.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  // If parsing fails, flag it for manual review
  analysis = {
    relevant: true,
    confidence: 'low',
    title: 'Manual Review Required',
    summary: 'GOB could not parse AI response. Please check the site manually.',
    link: siteData.url,
    reason: 'AI parsing error: ' + e.message
  };
}

return [{
  json: {
    ...siteData,
    analysis
  }
}];

// Build a nicely formatted Telegram message
const data = $input.first().json;
const analysis = data.analysis;

const confidenceEmoji = {
  'high': '🟢',
  'medium': '🟡',
  'low': '🔴'
}[analysis.confidence] || '⚪';

const lines = [
  `🏛️ *GOB ALERT* - New Govt Notification!`,
  ``,
  `📌 *${analysis.title}*`,
  ``,
  `📋 *Summary:*`,
  analysis.summary,
  ``,
  `🌐 *Source:* ${data.name}`,
  `${confidenceEmoji} *Confidence:* ${analysis.confidence}`,
];

if (analysis.link && analysis.link !== 'null' && analysis.link !== null) {
  lines.push(``);
  lines.push(`🔗 *Link:* ${analysis.link}`);
}

lines.push(``);
lines.push(`_Monitored by GOB 🤖 | ${new Date().toLocaleString('en-IN', {timeZone: 'Asia/Kolkata'})}_`);

return [{
  json: {
    ...data,
    telegram_message: lines.join('\n')
  }
}];

